import React, { useState, useEffect } from "react";
import DefaultLoginTemplate from "../components/templates/DefaultLoginTemplate";
import { getSupabase } from "../database/supabase";
import { useUniversalRouter } from "../database/routerViteGatsbyUniversal";
import { useIsLoggedIn } from "../database/useSupabaseIsLoggedIn";

const LoginPage = () => {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  // UI loading state (spinner)
  const [loading, setLoading] = useState(false);

  const [error, setError] = useState<string | null>(null);

  const { go } = useUniversalRouter();

  // Rename this so it doesn’t nuke your spinner
  const { isLoggedIn, loading: authChecking } = useIsLoggedIn();

  // If already logged in, bounce to CMS
  useEffect(() => {
    if (!authChecking && isLoggedIn) {
      console.log("[Auth] Already logged in → redirecting to /cms");
      go("/cms");
    }
  }, [authChecking, isLoggedIn]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    console.log("[Auth] Attempting login with:", email);

    try {
      const supabase = await getSupabase();

      const { data, error } = await supabase.auth.signInWithPassword({
        email,
        password,
      });

      console.log("[Auth] Supabase result:", data, error);

      if (error) {
        setError(error.message);
        return;
      }

      console.log("[Auth] Login successful via Supabase");
      go("/cms");

    } catch (err: any) {
      console.error("[Auth] Unexpected error:", err);
      setError("Something broke in Supabase. Check console.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <DefaultLoginTemplate
      email={email}
      password={password}
      onEmailChange={setEmail}
      onPasswordChange={setPassword}
      onSubmit={handleLogin}
      loading={loading}
      error={error}
    />
  );
};

export default LoginPage;