import React from "react";
import "./DefaultLoginTemplate.css";

export interface DefaultLoginTemplateProps {
    email: string;
    password: string;
    onEmailChange: (value: string) => void;
    onPasswordChange: (value: string) => void;
    onSubmit: (e: React.FormEvent) => void;
    loading: boolean;
    error: string | null;
}

const DefaultLoginTemplate: React.FC<DefaultLoginTemplateProps> = ({
    email,
    password,
    onEmailChange,
    onPasswordChange,
    onSubmit,
    loading,
    error,
}) => {
    return (
        <div className="login-wrapper">
            <div className="login-card">
                <div className="login-header">
                    <div className="login-logo">
                        <svg
                            width="32"
                            height="32"
                            viewBox="0 0 24 24"
                            fill="none"
                            stroke="currentColor"
                            strokeWidth="2.5"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        >
                            <path d="M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5" />
                        </svg>
                    </div>
                    <h1 className="login-title">Admin Portal</h1>
                    <p className="login-subtitle">Please enter your credentials to log in.</p>
                </div>

                {error && (
                    <div className="login-error">
                        <svg
                            width="16"
                            height="16"
                            viewBox="0 0 24 24"
                            fill="none"
                            stroke="currentColor"
                            strokeWidth="2"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                        >
                            <circle cx="12" cy="12" r="10" />
                            <line x1="12" y1="8" x2="12" y2="12" />
                            <line x1="12" y1="16" x2="12.01" y2="16" />
                        </svg>
                        {error}
                    </div>
                )}

                <form onSubmit={onSubmit} className="login-form">
                    <div className="form-group">
                        <label className="form-label">Email Address</label>
                        <div className="input-container">
                            <input
                                type="email"
                                className="login-input"
                                placeholder="admin@example.com"
                                value={email}
                                onChange={(e) => onEmailChange(e.target.value)}
                                disabled={loading}
                                required
                            />
                        </div>
                    </div>

                    <div className="form-group">
                        <label className="form-label">Password</label>
                        <div className="input-container">
                            <input
                                type="password"
                                className="login-input"
                                placeholder="••••••••"
                                value={password}
                                onChange={(e) => onPasswordChange(e.target.value)}
                                disabled={loading}
                                required
                            />
                        </div>
                    </div>

                    <div className="forgot-password">
                        <a href="/reset-password" className="forgot-password-link">
                            Forgot password?
                        </a>
                    </div>

                    <button type="submit" className="login-button" disabled={loading}>
                        {loading ? (
                            <div className="loading-dots">
                                <span></span>
                                <span></span>
                                <span></span>
                            </div>
                        ) : (
                            "Log In"
                        )}
                    </button>
                </form>

                <div className="login-footer">
                    <p>© 2026 CMS Admin. All rights reserved.</p>
                </div>
            </div>
        </div>
    );
};

export default DefaultLoginTemplate;
